using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── Build the IChatClient via MEAI ───────────────────────────────────────────
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// ── In-memory notebook shared with the agent tools ───────────────────────────
var notebook = new Notebook();

// ── Define tools ─────────────────────────────────────────────────────────────
var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWebAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ── Create the research agent ────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When the user gives you a topic:
        1. Use the SearchWeb tool multiple times with different queries to gather information.
        2. Use the SaveNote tool to record each key finding as you go.
        3. After researching, use the GetNotes tool to review all your notes.
        4. Finally, provide a well-structured summary with the key findings and their sources.
        Be thorough but concise. Always cite where information came from.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: tools);

// ── Interactive loop ─────────────────────────────────────────────────────────
Console.WriteLine("🔍 Research Agent Ready");
Console.WriteLine("   Enter a topic to research, or 'quit' to exit.\n");

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Topic> ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input) || input.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching… (the agent may call tools several times)\n");
    Console.ResetColor();

    try
    {
        var runOptions = new ChatClientAgentRunOptions
        {
            ChatOptions = new ChatOptions
            {
                Temperature = 0f,
                MaxOutputTokens = 4096,
            },
        };

        var response = await agent.RunAsync(input, session, runOptions);

        foreach (var message in response.Messages)
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
            {
                Console.ForegroundColor = ConsoleColor.Green;
                Console.WriteLine(message.Text);
                Console.ResetColor();
            }
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    // Clear notebook between topics so notes don't bleed across sessions.
    notebook.Clear();
    Console.WriteLine();
}

Console.WriteLine("Goodbye!");

