//  Tool implementations
// ═══════════════════════════════════════════════════════════════════════════════

/// <summary>Searches the web for information using the Wikipedia REST API.</summary>
[Description("Searches the web for information on a given query and returns a summary from Wikipedia. Use different phrasings to broaden research.")]
static async Task<string> SearchWebAsync(
    [Description("The search query")] string query,
    CancellationToken cancellationToken = default)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.Add("User-Agent", "ResearchAgent/1.0");

    try
    {
        // Use Wikipedia's search API for broader results.
        var encoded = Uri.EscapeDataString(query);
        var searchUrl = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=3&format=json";
        var searchJson = await http.GetStringAsync(searchUrl, cancellationToken);

        // Also try to get a direct summary.
        var summaryUrl = $"https://en.wikipedia.org/api/rest_v1/page/summary/{encoded}";
        string summary;
        try
        {
            summary = await http.GetStringAsync(summaryUrl, cancellationToken);
        }
        catch
        {
            summary = "";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Search results for: \"{query}\" ===");

        if (!string.IsNullOrEmpty(summary))
        {
            sb.AppendLine("[Direct summary]");
            // Truncate to keep context windows reasonable.
            sb.AppendLine(summary.Length > 2000 ? summary[..2000] : summary);
        }

        sb.AppendLine("[Search hits]");
        sb.AppendLine(searchJson.Length > 2000 ? searchJson[..2000] : searchJson);

        return sb.ToString();
    }
    catch (Exception ex)
    {
        return $"Search for \"{query}\" failed: {ex.Message}. Try a different phrasing.";
    }
}

