//  Notebook — holds research notes between tool calls
// ═══════════════════════════════════════════════════════════════════════════════

sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Saves a research note for later reference. Record key findings as you discover them.")]
    public string SaveNote([Description("The note to save")] string content)
    {
        _notes.Add(content);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieves all previously saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"Note #{i + 1}: {_notes[i]}");
        }

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

